<template>
	<view v-if="loaded" class="load-in-advance">
		<view class="shade"></view>
		<view class="load-content">
			已加载{{percent}}
		</view>
	</view>
	<view v-else>
		<view class="container">
			<slot></slot>
		</view>
	</view>
</template>

<script>
	export default {
		name:"LoadInAdvance",
		data() {
			return {
				loaded: true,
				count: 0,
				percent: '',
			};
		},
		props:["urls"],
		mounted() {
			console.info("loading");
			this.preLoad(); //预加载图片
		},
		watch: {
			count: function(val, old) {
				if (val === this.urls.length) { // 图片全部加载完成后跳转页面
					console.log('loaded')
					this.loaded = false;
				}
			},
		},
		methods:{
			preLoad() { //预加载图片
				const that = this;
				for (let url of this.urls) {
					uni.getImageInfo({
					        src: url,
					    success: function (image) {
							that.count++
							// 计算图片加载的百分数，绑定到percent变量
							let percentNum = Math.floor(that.count / that.urls.length * 100)
							that.percent = `${percentNum}%`
					    }
					});
				}
			},
		}
	}
</script>

<style lang="less" scoped>
.load-in-advance{
	position: relative;
	top: 0;
	left:0;
	width: 100vw;
	height: 100vh;
	z-index:101;
	.shade{
		position: absolute;
		top: 0;
		left: 0;
		width: 100%;
		height: 100%;
		background: #000;
		opacity: 0.5;
	}
	.load-content{
		color: red;
		font-size: 32rpx;
	}
	.container{
		box-sizing: border-box;
		width: 100%;
		height: 100vh;
		font-size: 14px;
		line-height: 24px;
	}
}
</style>